import { useLocale } from '../../../lib/i18n'
import type { GroupMember } from '../../../lib/types'

const TIER_KEY_MAP: Record<string, string> = {
  self: 'trust.self',
  privileged: 'trust.privileged',
  internal: 'trust.internal',
  known: 'trust.known',
}

function tierColor(tier: string | number): string {
  if (tier === 'self') return 'var(--accent-blue)'
  if (tier === 'privileged' || tier === 3) return 'var(--accent-purple)'
  if (tier === 'internal' || tier === 2) return 'var(--accent-green)'
  if (tier === 'known' || tier === 1) return 'var(--text-secondary)'
  return 'var(--text-muted)'
}

interface MemberSidebarProps {
  members: GroupMember[]
  selfWallet: string
}

export function MemberSidebar({ members, selfWallet }: MemberSidebarProps) {
  const { t } = useLocale()

  function tierLabel(tier: string | number): string {
    if (typeof tier === 'string' && TIER_KEY_MAP[tier]) return t(TIER_KEY_MAP[tier])
    if (tier === 3) return t('trust.privileged')
    if (tier === 2) return t('trust.internal')
    if (tier === 1) return t('trust.known')
    return t('trust.untrusted')
  }

  return (
    <div
      className="w-56 flex-shrink-0 overflow-y-auto py-4 px-3"
      style={{
        borderLeft: '1px solid var(--border)',
        background: 'var(--bg-secondary)',
      }}
    >
      <div className="text-xs font-medium mb-3 px-1" style={{ color: 'var(--text-muted)' }}>
        {t('chat.membersHeader', { n: members.length })}
      </div>
      <div className="space-y-1">
        {members.map(m => {
          const isSelf = m.wallet === selfWallet
          const color = tierColor(m.trust_tier)
          return (
            <div
              key={m.wallet}
              className="flex items-center gap-2 px-2 py-1.5"
              style={{ borderRadius: 'var(--radius-sm)' }}
            >
              <div
                className="w-6 h-6 flex items-center justify-center text-xs font-medium flex-shrink-0"
                style={{
                  borderRadius: 'var(--radius-sm)',
                  background: `color-mix(in srgb, ${color} 15%, transparent)`,
                  color,
                }}
              >
                {(m.name || '?')[0].toUpperCase()}
              </div>
              <div className="min-w-0 flex-1">
                <div className="text-xs truncate" style={{ color: 'var(--text-primary)' }}>
                  {m.name}{isSelf ? ' ' + t('chat.self') : ''}
                </div>
                <div
                  className="text-xs truncate"
                  style={{ color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: 10 }}
                >
                  {tierLabel(m.trust_tier)}
                </div>
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}
