import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { motion, AnimatePresence } from 'framer-motion'
import { fetchPeers, fetchSessions, postSessionAction } from '../../lib/api/client'
import { useLocale } from '../../lib/i18n'
import { PageHeader } from '../../components/PageHeader'
import { EmptyState } from '../../components/EmptyState'
import { StatusDot } from '../../components/StatusDot'
import { TrustBadge } from '../../components/TrustBadge'
import { PeerDrawer } from '../peers/PeerDrawer'
import { SESSION_STATE_COLORS } from '../../lib/constants'
import type { Peer, Session } from '../../lib/types'

/* ── Animation presets ──────────────────────────────────── */

const containerVariants = {
  hidden: {},
  visible: {
    transition: { staggerChildren: 0.06, ease: 'easeOut' as const },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 12 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.3, ease: 'easeOut' as const },
  },
  exit: { opacity: 0, y: -8, transition: { duration: 0.2, ease: 'easeIn' as const } },
}

/* ── Types ──────────────────────────────────────────────── */

type ViewMode = 'agents' | 'sessions'

const SESSION_FILTER_TABS = ['all', 'proposed', 'active', 'completed'] as const
type SessionFilter = (typeof SESSION_FILTER_TABS)[number]

/* ── Shared styles ──────────────────────────────────────── */

const cardStyle: React.CSSProperties = {
  background: 'var(--bg-secondary)',
  borderRadius: 'var(--radius-md)',
  border: '1px solid var(--border)',
  padding: 16,
  cursor: 'pointer',
  transition: 'border-color 0.2s ease, transform 0.15s ease',
}

const pillStyle: React.CSSProperties = {
  display: 'inline-block',
  padding: '2px 8px',
  fontSize: 12,
  borderRadius: 'var(--radius-sm)',
  border: '1px solid var(--border)',
  background: 'transparent',
  color: 'var(--text-secondary)',
  lineHeight: '18px',
}

const btnBase: React.CSSProperties = {
  border: 'none',
  borderRadius: 'var(--radius-sm)',
  padding: '6px 14px',
  fontSize: 13,
  fontWeight: 500,
  cursor: 'pointer',
  transition: 'opacity 0.15s',
}

/* ── Component ──────────────────────────────────────────── */

export function TeamPage() {
  const queryClient = useQueryClient()
  const { t } = useLocale()

  /* State */
  const [view, setView] = useState<ViewMode>('agents')
  const [search, setSearch] = useState('')
  const [sessionFilter, setSessionFilter] = useState<SessionFilter>('all')
  const [drawerPeerId, setDrawerPeerId] = useState<string | null>(null)

  /* Queries */
  const peersQuery = useQuery({
    queryKey: ['peers'],
    queryFn: fetchPeers,
    enabled: view === 'agents',
  })

  const sessionsQuery = useQuery({
    queryKey: ['sessions'],
    queryFn: () => fetchSessions(),
    enabled: view === 'sessions',
  })

  /* Mutations */
  const sessionAction = useMutation({
    mutationFn: ({ id, action }: { id: string; action: 'accept' | 'reject' | 'close' }) =>
      postSessionAction(id, action),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
    },
  })

  /* ── Derived data ─────────────────────────────────────── */

  const lowerSearch = search.toLowerCase()

  const filteredPeers = (peersQuery.data ?? [])
    .filter((p: Peer) => {
      if (!lowerSearch) return true
      return (
        p.name.toLowerCase().includes(lowerSearch) ||
        p.skills.some((s) => s.toLowerCase().includes(lowerSearch))
      )
    })
    .sort((a: Peer, b: Peer) => {
      if (a.is_online === b.is_online) return a.name.localeCompare(b.name)
      return a.is_online ? -1 : 1
    })

  const filteredSessions = (sessionsQuery.data ?? []).filter((s: Session) => {
    if (sessionFilter === 'all') return true
    return s.state === sessionFilter
  })

  /* Resolve peer name for sessions — best-effort from cached peers */
  const peerMap = new Map<string, Peer>()
  for (const p of peersQuery.data ?? []) {
    peerMap.set(p.wallet, p)
  }

  function peerNameFor(session: Session): string {
    return peerMap.get(session.peer_id)?.name ?? session.peer_id.slice(0, 10) + '...'
  }

  /* ── Render helpers ───────────────────────────────────── */

  function renderViewToggle() {
    return (
      <div
        className="inline-flex"
        style={{
          background: 'var(--bg-secondary)',
          borderRadius: 'var(--radius-sm)',
          padding: 2,
          border: '1px solid var(--border)',
        }}
      >
        {(['agents', 'sessions'] as const).map((v) => (
          <button
            key={v}
            onClick={() => setView(v)}
            style={{
              border: 'none',
              borderRadius: 'var(--radius-sm)',
              padding: '6px 16px',
              fontSize: 13,
              fontWeight: 500,
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              background: view === v ? 'var(--accent-red)' : 'transparent',
              color: view === v ? '#fff' : 'var(--text-secondary)',
            }}
          >
            {v === 'agents' ? t('team.agentView') : t('team.sessionView')}
          </button>
        ))}
      </div>
    )
  }

  function renderSearchBar() {
    return (
      <div style={{ position: 'relative', maxWidth: 360, flex: 1 }}>
        <svg
          width="16"
          height="16"
          viewBox="0 0 16 16"
          fill="none"
          style={{
            position: 'absolute',
            left: 12,
            top: '50%',
            transform: 'translateY(-50%)',
            color: 'var(--text-muted)',
          }}
        >
          <circle cx="7" cy="7" r="5.5" stroke="currentColor" strokeWidth="1.5" />
          <path d="M11 11L14 14" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" />
        </svg>
        <input
          type="text"
          placeholder={view === 'agents' ? t('team.searchAgents') : t('team.searchSessions')}
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={{
            width: '100%',
            padding: '8px 12px 8px 36px',
            border: '1px solid var(--border)',
            borderRadius: 'var(--radius-sm)',
            fontSize: 13,
            color: 'var(--text-primary)',
            background: 'var(--bg-secondary)',
            outline: 'none',
            transition: 'border-color 0.2s',
          }}
          onFocus={(e) => (e.currentTarget.style.borderColor = 'var(--accent-red)')}
          onBlur={(e) => (e.currentTarget.style.borderColor = 'var(--border)')}
        />
      </div>
    )
  }

  /* ── Agent View ───────────────────────────────────────── */

  function renderAgentView() {
    if (peersQuery.isLoading) {
      return (
        <div className="flex justify-center py-16" style={{ color: 'var(--text-muted)' }}>
          {t('team.loadingAgents')}
        </div>
      )
    }

    if (!filteredPeers.length) {
      return (
        <EmptyState
          title={search ? t('team.noAgents') : t('team.noPeers')}
          description={search ? t('team.noAgentsDesc') : t('team.noPeersDesc')}
        />
      )
    }

    return (
      <motion.div
        className="grid gap-3"
        style={{ gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))' }}
        variants={containerVariants}
        initial="hidden"
        animate="visible"
      >
        <AnimatePresence mode="popLayout">
          {filteredPeers.map((peer: Peer) => (
            <motion.div
              key={peer.wallet}
              variants={itemVariants}
              layout
              exit={itemVariants.exit}
              style={{
                ...cardStyle,
                borderLeft: peer.is_online ? '3px solid var(--accent-green)' : undefined,
              }}
              onClick={() => setDrawerPeerId(peer.wallet)}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = 'var(--text-muted)'
                e.currentTarget.style.transform = 'translateY(-2px)'
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.border = '1px solid var(--border)'
                if (peer.is_online) {
                  e.currentTarget.style.borderLeft = '3px solid var(--accent-green)'
                }
                e.currentTarget.style.transform = 'translateY(0)'
              }}
            >
              {/* Header: status + name */}
              <div className="flex items-center gap-2 mb-2">
                <StatusDot status={peer.is_online ? 'online' : 'offline'} />
                <span
                  className="font-medium text-sm truncate"
                  style={{ color: 'var(--text-primary)' }}
                >
                  {peer.name}
                </span>
                <div className="ml-auto">
                  <TrustBadge tier={peer.trust_tier} />
                </div>
              </div>

              {/* Skills */}
              <div className="flex flex-wrap gap-1 mb-2" style={{ minHeight: 22 }}>
                {peer.skills.slice(0, 3).map((skill) => (
                  <span key={skill} style={pillStyle}>
                    {skill}
                  </span>
                ))}
                {peer.skills.length > 3 && (
                  <span
                    style={{
                      ...pillStyle,
                      border: 'none',
                      background: 'transparent',
                      color: 'var(--text-muted)',
                    }}
                  >
                    +{peer.skills.length - 3}
                  </span>
                )}
              </div>

              {/* Footer: skill count + latency */}
              <div
                className="flex items-center justify-between text-xs"
                style={{ color: 'var(--text-muted)' }}
              >
                <span>{t('team.skills', { n: peer.skills.length })}</span>
                {peer.latency_ms != null && (
                  <span style={{ fontFamily: 'monospace', fontSize: 11 }}>
                    {peer.latency_ms}ms
                  </span>
                )}
              </div>
            </motion.div>
          ))}
        </AnimatePresence>
      </motion.div>
    )
  }

  /* ── Session View ─────────────────────────────────────── */

  function renderSessionFilterTabs() {
    return (
      <div className="flex gap-1 mb-4">
        {SESSION_FILTER_TABS.map((tab) => (
          <button
            key={tab}
            onClick={() => setSessionFilter(tab)}
            style={{
              border: sessionFilter === tab ? 'none' : '1px solid var(--border)',
              borderRadius: 'var(--radius-sm)',
              padding: '5px 14px',
              fontSize: 13,
              fontWeight: 500,
              cursor: 'pointer',
              transition: 'all 0.2s ease',
              background: sessionFilter === tab ? 'var(--accent-red)' : 'transparent',
              color: sessionFilter === tab ? '#fff' : 'var(--text-secondary)',
            }}
          >
            {t('session.' + tab)}
          </button>
        ))}
      </div>
    )
  }

  function renderSessionView() {
    if (sessionsQuery.isLoading) {
      return (
        <div className="flex justify-center py-16" style={{ color: 'var(--text-muted)' }}>
          {t('team.loadingSessions')}
        </div>
      )
    }

    return (
      <>
        {renderSessionFilterTabs()}

        {!filteredSessions.length ? (
          <EmptyState
            title={t('team.noSessions')}
            description={
              sessionFilter === 'all'
                ? t('team.noSessionsDesc')
                : t('team.noSessionsFiltered', { state: t('session.' + sessionFilter) })
            }
          />
        ) : (
          <motion.div
            className="flex flex-col gap-3"
            variants={containerVariants}
            initial="hidden"
            animate="visible"
          >
            <AnimatePresence mode="popLayout">
              {filteredSessions.map((session: Session) => {
                const name = peerNameFor(session)
                const stateColor = SESSION_STATE_COLORS[session.state] ?? 'var(--text-muted)'
                const isProposedResponder =
                  session.state === 'proposed' && session.role === 'responder'
                const isActive = session.state === 'active'

                return (
                  <motion.div
                    key={session.session_id}
                    variants={itemVariants}
                    layout
                    exit={itemVariants.exit}
                    style={{
                      ...cardStyle,
                      cursor: 'default',
                      borderLeft: `3px solid ${stateColor}`,
                    }}
                  >
                    {/* Top row */}
                    <div className="flex items-center gap-2 mb-2">
                      <span
                        className="font-medium text-sm"
                        style={{ color: 'var(--text-primary)' }}
                      >
                        {name}
                      </span>

                      {/* State badge */}
                      <span
                        className="text-xs font-medium px-2 py-0.5"
                        style={{
                          color: stateColor,
                          border: `1px solid ${stateColor}`,
                          background: 'transparent',
                          borderRadius: 'var(--radius-sm)',
                        }}
                      >
                        {t('session.' + session.state)}
                      </span>

                      {/* Role */}
                      <span
                        className="text-xs"
                        style={{ color: 'var(--text-muted)', marginLeft: 'auto' }}
                      >
                        {session.role}
                      </span>
                    </div>

                    {/* Skills */}
                    <div className="flex flex-wrap gap-1 mb-3">
                      {(session.agreed_skills.length
                        ? session.agreed_skills
                        : session.proposed_skills
                      ).map((skill) => (
                        <span key={skill} style={pillStyle}>
                          {skill}
                        </span>
                      ))}
                    </div>

                    {/* Stats row */}
                    <div
                      className="flex items-center gap-4 text-xs mb-3"
                      style={{ color: 'var(--text-muted)' }}
                    >
                      <span>
                        {t('team.calls', { used: session.call_count, max: session.agreed_max_calls })}
                      </span>
                      <span>
                        {t('team.completed', { n: session.tasks_completed })}
                      </span>
                      {session.tasks_failed > 0 && (
                        <span style={{ color: 'var(--accent-red)' }}>
                          {t('team.failed', { n: session.tasks_failed })}
                        </span>
                      )}
                    </div>

                    {/* Actions */}
                    {isProposedResponder && (
                      <div className="flex gap-2">
                        <button
                          style={{
                            ...btnBase,
                            background: 'var(--accent-green)',
                            color: '#fff',
                          }}
                          disabled={sessionAction.isPending}
                          onClick={() =>
                            sessionAction.mutate({
                              id: session.session_id,
                              action: 'accept',
                            })
                          }
                        >
                          {t('team.accept')}
                        </button>
                        <button
                          style={{
                            ...btnBase,
                            background: 'var(--accent-red)',
                            color: '#fff',
                          }}
                          disabled={sessionAction.isPending}
                          onClick={() =>
                            sessionAction.mutate({
                              id: session.session_id,
                              action: 'reject',
                            })
                          }
                        >
                          {t('team.reject')}
                        </button>
                      </div>
                    )}

                    {isActive && (
                      <div className="flex gap-2">
                        <button
                          style={{
                            ...btnBase,
                            background: 'transparent',
                            border: '1px solid var(--border)',
                            color: 'var(--text-primary)',
                          }}
                          disabled={sessionAction.isPending}
                          onClick={() =>
                            sessionAction.mutate({
                              id: session.session_id,
                              action: 'close',
                            })
                          }
                        >
                          {t('team.closeSession')}
                        </button>
                      </div>
                    )}
                  </motion.div>
                )
              })}
            </AnimatePresence>
          </motion.div>
        )}
      </>
    )
  }

  /* ── Main render ──────────────────────────────────────── */

  return (
    <div>
      <PageHeader
        title={t('team.title')}
        description={t('team.desc')}
        actions={renderViewToggle()}
      />

      <div className="flex items-center gap-3 mb-5">{renderSearchBar()}</div>

      {view === 'agents' ? renderAgentView() : renderSessionView()}

      {/* Peer drawer */}
      <AnimatePresence>
        {drawerPeerId && (
          <PeerDrawer peerId={drawerPeerId} onClose={() => setDrawerPeerId(null)} />
        )}
      </AnimatePresence>
    </div>
  )
}
