import { useLocale } from '../../lib/i18n'

const LEVELS = [
  {
    value: 0 as const,
    labelKey: 'settings.autonomy.manual',
    descKey: 'settings.autonomy.manualDesc',
    color: 'var(--accent-red)',
  },
  {
    value: 1 as const,
    labelKey: 'settings.autonomy.ask',
    descKey: 'settings.autonomy.askDesc',
    color: 'var(--accent-yellow)',
  },
  {
    value: 2 as const,
    labelKey: 'settings.autonomy.auto',
    descKey: 'settings.autonomy.autoDesc',
    color: 'var(--accent-green)',
  },
]

interface AutonomyDialProps {
  level: 0 | 1 | 2
  onChange: (level: 0 | 1 | 2) => void
  saving?: boolean
}

export function AutonomyDial({ level, onChange, saving }: AutonomyDialProps) {
  const { t } = useLocale()

  return (
    <div
      className="p-5"
      style={{ boxShadow: 'var(--shadow-sm)', borderRadius: 'var(--radius-md)', background: 'var(--bg-primary)' }}
    >
      <h3
        className="text-base font-semibold mb-4"
        style={{ color: 'var(--text-primary)' }}
      >
        {t('settings.autonomy.current')}
      </h3>

      <div className="space-y-3">
        {LEVELS.map(opt => {
          const active = level === opt.value
          return (
            <button
              key={opt.value}
              onClick={() => onChange(opt.value)}
              disabled={saving}
              className="w-full text-left p-4 transition-colors"
              style={{
                borderRadius: 'var(--radius-sm)',
                border: 'none',
                background: active ? `color-mix(in srgb, ${opt.color} 8%, white)` : 'var(--bg-secondary)',
                opacity: saving ? 0.6 : 1,
              }}
            >
              <div className="flex items-center gap-2 mb-1">
                <span
                  className="w-2.5 h-2.5 rounded-full"
                  style={{ background: active ? opt.color : 'var(--text-muted)' }}
                />
                <span className="text-sm font-medium" style={{ color: 'var(--text-primary)' }}>{t(opt.labelKey)}</span>
                {active && (
                  <span
                    className="text-xs px-2 py-0.5"
                    style={{
                      background: `color-mix(in srgb, ${opt.color} 10%, white)`,
                      borderRadius: 'var(--radius-sm)',
                      color: opt.color,
                      fontWeight: 500,
                    }}
                  >
                    {t('settings.autonomy.current')}
                  </span>
                )}
              </div>
              <p className="text-xs ml-4.5" style={{ color: 'var(--text-muted)' }}>
                {t(opt.descKey)}
              </p>
            </button>
          )
        })}
      </div>

      {saving && (
        <div className="text-xs mt-3" style={{ color: 'var(--text-muted)' }}>{t('settings.autonomy.saving')}</div>
      )}
    </div>
  )
}
