/**
 * AgentIcon — generates a unique geometric pattern from an agent name.
 * Like GitHub identicons but simpler. Each agent gets a visually distinct icon.
 *
 * Uses a 5x5 grid with vertical symmetry. The pattern and color are
 * deterministically derived from the name string.
 */

interface AgentIconProps {
  name: string;
  size?: number;
}

// Simple hash from string
function hashCode(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) - hash + str.charCodeAt(i)) | 0;
  }
  return Math.abs(hash);
}

// Muted, professional hues (not bright/AI-looking)
const HUES = [
  { bg: '#E8E4E0', fg: '#8B7E74' },  // warm stone
  { bg: '#E0E8E4', fg: '#6B8B7B' },  // sage
  { bg: '#E4E0E8', fg: '#7B6B8B' },  // muted purple
  { bg: '#E8E4E0', fg: '#8B7468' },  // terracotta
  { bg: '#E0E4E8', fg: '#6B7B8B' },  // slate blue
  { bg: '#E8E8E0', fg: '#7B7B5E' },  // olive
  { bg: '#E4E8E0', fg: '#6B8B6B' },  // forest
  { bg: '#E8E0E4', fg: '#8B6B7B' },  // dusty rose
];

export function AgentIcon({ name, size = 28 }: AgentIconProps) {
  const hash = hashCode(name);
  const palette = HUES[hash % HUES.length];

  // Generate 5x3 grid (left half + center), mirror for symmetry
  const cells: boolean[] = [];
  for (let i = 0; i < 15; i++) {
    cells.push(((hash >> (i % 30)) & 1) === 1);
  }

  // Build 5x5 with vertical symmetry
  const grid: boolean[][] = [];
  for (let row = 0; row < 5; row++) {
    const r: boolean[] = [];
    for (let col = 0; col < 5; col++) {
      const mirrorCol = col > 2 ? 4 - col : col;
      r.push(cells[row * 3 + mirrorCol]);
    }
    grid.push(r);
  }

  const cellSize = size / 7; // 5 cells + 1 padding on each side
  const padding = cellSize;

  return (
    <svg
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      style={{ borderRadius: 'var(--radius-sm)', flexShrink: 0 }}
    >
      <rect width={size} height={size} fill={palette.bg} rx={3} />
      {grid.map((row, y) =>
        row.map((on, x) =>
          on ? (
            <rect
              key={`${y}-${x}`}
              x={padding + x * cellSize}
              y={padding + y * cellSize}
              width={cellSize}
              height={cellSize}
              fill={palette.fg}
              rx={1}
            />
          ) : null
        )
      )}
    </svg>
  );
}
