import { create } from 'zustand'
import en from './en'
import zh from './zh'

export type Locale = 'en' | 'zh'

const messages: Record<Locale, Record<string, string>> = { en, zh }

function getInitialLocale(): Locale {
  try {
    const saved = localStorage.getItem('coworker-locale')
    if (saved === 'en' || saved === 'zh') return saved
  } catch {}
  // Default based on browser language
  if (typeof navigator !== 'undefined' && navigator.language.startsWith('zh')) return 'zh'
  return 'en'
}

interface LocaleStore {
  locale: Locale
  setLocale: (locale: Locale) => void
}

export const useLocaleStore = create<LocaleStore>((set) => ({
  locale: getInitialLocale(),
  setLocale: (locale) => {
    try { localStorage.setItem('coworker-locale', locale) } catch {}
    set({ locale })
  },
}))

/**
 * Translation hook. Returns `t` function and locale controls.
 *
 * Usage:
 *   const { t, locale, setLocale } = useLocale()
 *   t('nav.home')           // → "Home" or "首页"
 *   t('home.activeSessions', { n: 3 })  // → "3 active sessions"
 */
export function useLocale() {
  const { locale, setLocale } = useLocaleStore()

  function t(key: string, params?: Record<string, string | number>): string {
    let str = messages[locale]?.[key] ?? messages.en[key] ?? key
    if (params) {
      for (const [k, v] of Object.entries(params)) {
        str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), String(v))
      }
    }
    return str
  }

  return { t, locale, setLocale }
}

/**
 * Non-hook version for use outside React components (e.g. constants).
 * Returns the translation for the current locale.
 */
export function getT() {
  const locale = useLocaleStore.getState().locale
  return function t(key: string, params?: Record<string, string | number>): string {
    let str = messages[locale]?.[key] ?? messages.en[key] ?? key
    if (params) {
      for (const [k, v] of Object.entries(params)) {
        str = str.replace(new RegExp(`\\{${k}\\}`, 'g'), String(v))
      }
    }
    return str
  }
}
