import { useRef, useCallback } from 'react'
import { useQuery, useQueryClient } from '@tanstack/react-query'
import { fetchConversationMessages } from '../../../lib/api/client'
import type { DmMessage, ChatMessage } from '../../../lib/types'

type AnyMessage = DmMessage | ChatMessage

function dedup(msgs: AnyMessage[]): AnyMessage[] {
  const seen = new Set<string>()
  const result: AnyMessage[] = []
  for (const m of msgs) {
    if (!seen.has(m.id)) {
      seen.add(m.id)
      result.push(m)
    }
  }
  return result.sort((a, b) => a.created_at.localeCompare(b.created_at))
}

/**
 * Incrementally fetches conversation messages using cursor-based polling.
 * Works for both DM and Group conversations via the unified /api/messages endpoint.
 */
export function useConversationMessagesQuery(
  conversationId: string | null,
  pollInterval = 2000,
) {
  const queryClient = useQueryClient()
  const cursorsRef = useRef<Map<string, string>>(new Map())

  const queryKey = ['conversation-messages', conversationId]

  const query = useQuery({
    queryKey,
    queryFn: async (): Promise<AnyMessage[]> => {
      if (!conversationId) return []

      const requestId = conversationId
      const cursor = cursorsRef.current.get(requestId) ?? undefined

      const res = await fetchConversationMessages(requestId, {
        after: cursor,
        limit: 50,
      })

      if (res.paging.last_message_id) {
        cursorsRef.current.set(requestId, res.paging.last_message_id)
      }

      const prev = queryClient.getQueryData<AnyMessage[]>(
        ['conversation-messages', requestId],
      ) ?? []
      return dedup([...prev, ...res.messages])
    },
    enabled: !!conversationId,
    refetchInterval: pollInterval,
    placeholderData: (prev) => prev,
  })

  const resetCursor = useCallback((id?: string) => {
    if (id) {
      cursorsRef.current.delete(id)
    } else {
      cursorsRef.current.clear()
    }
  }, [])

  return { ...query, resetCursor }
}
