import { TRUST_TIER_LABELS, TRUST_TIER_COLORS } from '../lib/constants';
import { useLocale } from '../lib/i18n';

interface TrustBadgeProps {
  tier: number;
}

export function TrustBadge({ tier }: TrustBadgeProps) {
  const { t } = useLocale();
  const label = TRUST_TIER_LABELS[tier] ? t(TRUST_TIER_LABELS[tier]) : `Tier ${tier}`;
  const color = TRUST_TIER_COLORS[tier] || 'var(--text-muted)';

  return (
    <span
      className="inline-flex items-center px-1.5 py-0.5 text-xs"
      style={{
        color,
        background: 'var(--bg-primary)',
        border: `1px solid ${color}`,
        borderRadius: 'var(--radius-sm)',
        fontSize: 10,
        fontWeight: 500,
        opacity: 0.85,
      }}
    >
      {label}
    </span>
  )
}
