import { useQuery } from '@tanstack/react-query'
import { motion } from 'framer-motion'
import { fetchCollabStatus } from '../../lib/api/client'
import { PageHeader } from '../../components/PageHeader'
import { EmptyState } from '../../components/EmptyState'
import { useLocale } from '../../lib/i18n'

const fadeUp = {
  initial: { opacity: 0, y: 12 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.3, ease: 'easeOut' as const },
}

function progressColor(pct: number): string {
  if (pct >= 100) return 'var(--accent-green)'
  if (pct >= 60) return 'var(--accent-green)'
  if (pct >= 30) return 'var(--accent-yellow)'
  return 'var(--accent-red)'
}

function krStatusColor(status: string): string {
  if (status === 'completed') return 'var(--accent-green)'
  if (status === 'in_progress') return 'var(--accent-red)'
  if (status === 'at_risk') return 'var(--accent-red)'
  return 'var(--text-muted)'
}

export function GoalsPage() {
  const { t } = useLocale()
  const { data: collab, isLoading, isError } = useQuery({
    queryKey: ['collab-status'],
    queryFn: fetchCollabStatus,
    refetchInterval: (query) => {
      // Only poll actively during running collaborations; idle = slow poll
      const status = query.state.data?.status
      if (status === 'executing' || status === 'proposing' || status === 'discovering') return 2000
      if (status === 'completed' || status === 'failed' || status === 'partial') return false
      return 10000  // idle — check occasionally
    },
    retry: 1,
  })

  const hasOkr = collab?.okr && (collab.okr.key_results?.length ?? 0) > 0
  const okr = collab?.okr
  const overallPct = okr?.overall_progress ?? 0

  return (
    <div>
      <PageHeader
        title={t('goals.title')}
        description={t('goals.desc')}
        actions={
          hasOkr ? (
            <div
              className="flex items-center gap-2 px-3 py-1.5"
              style={{
                border: `1px solid ${progressColor(overallPct)}`,
                color: progressColor(overallPct),
                borderRadius: 'var(--radius-sm)',
                fontWeight: 700,
                fontSize: 14,
              }}
            >
              {t('goals.overall', { pct: overallPct })}
            </div>
          ) : undefined
        }
      />

      {isLoading ? (
        <div className="text-sm" style={{ color: 'var(--text-muted)' }}>{t('goals.loadingCollab')}</div>
      ) : isError ? (
        <EmptyState
          title={t('goals.noConnect')}
          description={t('goals.noConnectDesc')}
        />
      ) : !hasOkr ? (
        <EmptyState
          title={t('goals.noOKR')}
          description={t('goals.noOKRDesc')}
        />
      ) : (
        <div>
          {/* Objective banner */}
          <motion.div
            {...fadeUp}
            className="p-5 mb-6"
            style={{
              background: 'var(--bg-secondary)',
              border: '1px solid var(--border)',
              borderRadius: 'var(--radius-lg)',
              borderLeft: '3px solid var(--accent-red)',
            }}
          >
            <div className="text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px' }}>
              {t('goals.objective')}
            </div>
            <div className="text-lg font-bold mb-3" style={{ color: 'var(--text-primary)', fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif" }}>
              {collab?.goal}
            </div>
            <div className="flex items-center gap-3">
              <div className="flex-1 h-2 overflow-hidden" style={{ background: 'var(--bg-primary)', borderRadius: 'var(--radius-sm)' }}>
                <div className="h-full transition-all duration-500" style={{ width: `${overallPct}%`, background: progressColor(overallPct), borderRadius: 'var(--radius-sm)' }} />
              </div>
              <span className="text-sm font-bold" style={{ color: progressColor(overallPct), minWidth: 40, textAlign: 'right' }}>
                {overallPct}%
              </span>
            </div>
            {collab?.agents && (
              <div className="flex items-center gap-4 mt-4 pt-4" style={{ borderTop: '1px solid var(--border)' }}>
                {(['alpha', 'beta'] as const).map((key) => {
                  const agent = collab.agents![key]
                  if (!agent) return null
                  return (
                    <div key={key} className="flex items-center gap-2 text-xs">
                      <span className="w-2 h-2 rounded-full" style={{ background: agent.online ? 'var(--accent-green)' : 'var(--text-muted)' }} />
                      <span style={{ color: 'var(--text-secondary)', fontWeight: 500 }}>{agent.name}</span>
                      <span style={{ color: 'var(--text-muted)' }}>{t('team.skills', { n: agent.skills?.length ?? 0 })}</span>
                    </div>
                  )
                })}
                {collab?.session && (
                  <div className="ml-auto flex items-center gap-3 text-xs" style={{ color: 'var(--text-muted)' }}>
                    <span>{t('privacy.' + collab.session.privacy)}</span>
                    <span>{t('trust.' + collab.session.trust)}</span>
                    <span>{t('team.calls', { used: collab.session.calls_used, max: collab.session.calls_max })}</span>
                  </div>
                )}
              </div>
            )}
          </motion.div>

          {/* Key Results */}
          <div className="mb-4" style={{ fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif", fontSize: 18, color: 'var(--text-primary)' }}>
            {t('goals.keyResults')}
          </div>
          <div className="space-y-4">
            {okr!.key_results.map((kr, i) => (
              <motion.div
                key={kr.kr_id}
                initial={{ opacity: 0, y: 12 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.3, delay: i * 0.08, ease: 'easeOut' as const }}
                className="p-5"
                style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)', borderLeft: '3px solid var(--accent-red)' }}
              >
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                    <span className="text-xs font-bold px-2 py-0.5" style={{
                      border: `1px solid ${krStatusColor(kr.status)}`,
                      color: krStatusColor(kr.status), borderRadius: 'var(--radius-sm)',
                    }}>
                      {kr.kr_id}
                    </span>
                    <span className="text-sm font-semibold" style={{ color: 'var(--text-primary)' }}>{kr.description}</span>
                  </div>
                  <span className="text-sm font-bold" style={{ color: krStatusColor(kr.status) }}>{kr.progress}%</span>
                </div>
                <div className="text-xs mb-3" style={{ color: 'var(--text-muted)' }}>
                  {kr.metric} — {t('goals.tasks', { done: kr.completed_count, total: kr.task_count })}
                </div>
                <div className="h-1.5 overflow-hidden" style={{ background: 'var(--bg-primary)', borderRadius: 'var(--radius-sm)' }}>
                  <div className="h-full transition-all duration-500" style={{ width: `${kr.progress}%`, background: krStatusColor(kr.status), borderRadius: 'var(--radius-sm)' }} />
                </div>

                {/* Tasks */}
                {collab?.steps && (
                  <div className="mt-3">
                    {collab.steps.filter((s) => s.kr_id === kr.kr_id).map((step) => {
                      const done = step.status === 'completed'
                      const running = step.status === 'running'
                      const failed = step.status === 'failed'
                      return (
                        <div key={step.index} className="flex items-center gap-2 text-xs py-1.5 px-2"
                          style={{ borderBottom: '1px solid var(--border)', background: running ? 'var(--accent-red-light)' : failed ? 'var(--accent-red-light)' : 'transparent' }}>
                          <span style={{ color: done ? 'var(--accent-green)' : running ? 'var(--accent-red)' : failed ? 'var(--accent-red)' : 'var(--text-muted)', fontWeight: 600 }}>
                            {done ? '✓' : running ? '◎' : failed ? '✗' : '○'}
                          </span>
                          <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 12, fontWeight: 500,
                            color: done ? 'var(--text-primary)' : running ? 'var(--accent-red)' : failed ? 'var(--accent-red)' : 'var(--text-muted)' }}>
                            {step.skill}
                          </span>
                          <span className="ml-auto flex items-center gap-2">
                            <span className="px-1.5 py-0.5" style={{ fontSize: 10, fontWeight: 600, borderRadius: 4,
                              border: step.agent.includes('alpha') ? '1px solid var(--accent-red)' : '1px solid var(--accent-yellow)',
                              color: step.agent.includes('alpha') ? 'var(--accent-red)' : 'var(--accent-yellow)' }}>
                              {step.agent.includes('alpha') ? 'Alpha' : 'Beta'}
                            </span>
                            {step.duration_ms != null && (
                              <span style={{ fontFamily: "'JetBrains Mono', monospace", color: 'var(--text-muted)' }}>
                                {(step.duration_ms / 1000).toFixed(1)}s
                              </span>
                            )}
                          </span>
                        </div>
                      )
                    })}
                  </div>
                )}
              </motion.div>
            ))}
          </div>

          {/* Cost */}
          {collab?.cost && (
            <motion.div {...fadeUp} transition={{ ...fadeUp.transition, delay: 0.3 }}
              className="p-5 mt-6" style={{ background: 'var(--bg-secondary)', border: '1px solid var(--border)', borderRadius: 'var(--radius-md)' }}>
              <div className="text-xs font-semibold mb-3" style={{ color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.5px', fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif" }}>
                {t('goals.cost')}
              </div>
              {(['alpha', 'beta'] as const).map((key) => {
                const ms = collab.cost![key]?.total_ms || 0
                const maxMs = Math.max(collab.cost!.alpha.total_ms, collab.cost!.beta.total_ms, 1)
                return (
                  <div key={key} className="flex items-center gap-3 mb-2 text-sm">
                    <span className="w-16 font-medium" style={{ color: 'var(--text-secondary)' }}>{key === 'alpha' ? 'Alpha' : key === 'beta' ? 'Beta' : key}</span>
                    <div className="flex-1 h-1.5 overflow-hidden" style={{ background: 'var(--bg-primary)', borderRadius: 3 }}>
                      <div className="h-full transition-all" style={{ width: `${(ms / maxMs) * 100}%`, background: key === 'alpha' ? 'var(--accent-red)' : 'var(--accent-yellow)', borderRadius: 3 }} />
                    </div>
                    <span className="text-xs" style={{ fontFamily: "'JetBrains Mono', monospace", color: 'var(--text-muted)', minWidth: 50, textAlign: 'right' }}>
                      {(ms / 1000).toFixed(1)}s
                    </span>
                  </div>
                )
              })}
            </motion.div>
          )}
        </div>
      )}
    </div>
  )
}
