import { useQuery } from '@tanstack/react-query'
import { useState } from 'react'
import { PageHeader } from '../../components/PageHeader'
import { useLocale } from '../../lib/i18n'

async function fetchInvite() {
  const res = await fetch('/api/invite')
  if (!res.ok) throw new Error('Failed to fetch invite')
  return res.json() as Promise<{
    invite_code: string
    short_code: string
    wallet: string
    name: string
    cli_command: string
  }>
}

export function InvitePage() {
  const { t } = useLocale()
  const [copied, setCopied] = useState<string | null>(null)

  const { data: invite, isLoading } = useQuery({
    queryKey: ['invite'],
    queryFn: fetchInvite,
  })

  function copyToClipboard(text: string, label: string) {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(label)
      setTimeout(() => setCopied(null), 2000)
    })
  }

  if (isLoading || !invite) {
    return (
      <div className="p-8">
        <PageHeader title={t('invite.title')} description={t('invite.subtitle')} />
        <div className="mt-8" style={{ color: 'var(--text-muted)' }}>
          {t('common.loading')}
        </div>
      </div>
    )
  }

  const items = [
    {
      label: t('invite.cliCommand'),
      value: invite.cli_command,
      key: 'cli',
      description: t('invite.cliDesc'),
    },
    {
      label: t('invite.inviteCode'),
      value: invite.invite_code,
      key: 'code',
      description: t('invite.codeDesc'),
    },
    {
      label: t('invite.wallet'),
      value: invite.wallet,
      key: 'wallet',
      description: t('invite.walletDesc'),
    },
  ]

  return (
    <div className="p-8 max-w-2xl">
      <PageHeader title={t('invite.title')} description={t('invite.subtitle')} />

      {/* Agent info */}
      <div
        className="mt-6 p-4"
        style={{
          background: 'var(--bg-secondary)',
          border: '1px solid var(--border)',
          borderRadius: 'var(--radius-lg)',
        }}
      >
        <div className="flex items-center gap-3">
          <div
            className="w-10 h-10 flex items-center justify-center text-lg font-bold"
            style={{
              background: 'var(--bg-tertiary)',
              borderRadius: 'var(--radius-md)',
              color: 'var(--text-primary)',
            }}
          >
            {invite.name[0]?.toUpperCase()}
          </div>
          <div>
            <div className="font-semibold" style={{ color: 'var(--text-primary)' }}>
              {invite.name}
            </div>
            <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
              {invite.short_code}
            </div>
          </div>
        </div>
      </div>

      {/* Shareable items */}
      <div className="mt-6 space-y-4">
        {items.map(({ label, value, key, description }) => (
          <div
            key={key}
            className="p-4"
            style={{
              background: 'var(--bg-secondary)',
              border: '1px solid var(--border)',
              borderRadius: 'var(--radius-lg)',
            }}
          >
            <div className="flex items-center justify-between mb-2">
              <span className="text-sm font-medium" style={{ color: 'var(--text-primary)' }}>
                {label}
              </span>
              <button
                onClick={() => copyToClipboard(value, key)}
                className="px-3 py-1 text-xs font-medium transition-all"
                style={{
                  borderRadius: 'var(--radius-sm)',
                  border: '1px solid var(--border)',
                  background: copied === key ? 'var(--accent-green-light)' : 'var(--bg-primary)',
                  color: copied === key ? 'var(--accent-green)' : 'var(--text-secondary)',
                }}
              >
                {copied === key ? t('invite.copied') : t('invite.copy')}
              </button>
            </div>
            <div
              className="text-xs p-2 font-mono break-all"
              style={{
                background: 'var(--bg-primary)',
                borderRadius: 'var(--radius-sm)',
                color: 'var(--text-secondary)',
                border: '1px solid var(--border)',
              }}
            >
              {value}
            </div>
            <div className="text-xs mt-2" style={{ color: 'var(--text-muted)' }}>
              {description}
            </div>
          </div>
        ))}
      </div>

      {/* How it works */}
      <div
        className="mt-6 p-4"
        style={{
          background: 'var(--bg-secondary)',
          border: '1px solid var(--border)',
          borderRadius: 'var(--radius-lg)',
        }}
      >
        <div className="text-sm font-medium mb-3" style={{ color: 'var(--text-primary)' }}>
          {t('invite.howItWorks')}
        </div>
        <div className="space-y-2 text-xs" style={{ color: 'var(--text-secondary)' }}>
          <div>1. {t('invite.step1')}</div>
          <div>2. {t('invite.step2')}</div>
          <div>3. {t('invite.step3')}</div>
        </div>
      </div>
    </div>
  )
}
