import { useState, useEffect, useCallback } from 'react'
import { useQuery } from '@tanstack/react-query'
import { motion } from 'framer-motion'
import { fetchConversations, fetchGroupDetail, fetchAgentProfile } from '../../lib/api/client'
import { useLocale } from '../../lib/i18n'
import { useConversationMessagesQuery } from './hooks/useConversationMessagesQuery'
import { ChatHeader } from './components/ChatHeader'
import { MessageList } from './components/MessageList'
import { Composer } from './components/Composer'
import { MemberSidebar } from './components/MemberSidebar'
import { EmptyState } from '../../components/EmptyState'
import type { ConversationSummary, GroupMember, ChatMessage, DmMessage } from '../../lib/types'

/* ── Protocol badge colors ── */
const phaseBadge: Record<string, { label: string; bg: string; fg: string }> = {
  discover: { label: 'Discover', bg: 'rgba(59,130,246,0.12)', fg: 'var(--accent-blue)' },
  plan: { label: 'Plan', bg: 'rgba(139,92,246,0.12)', fg: 'var(--accent-purple)' },
  execute: { label: 'Execute', bg: 'rgba(34,197,94,0.12)', fg: 'var(--accent-green)' },
  report: { label: 'Report', bg: 'rgba(245,158,11,0.12)', fg: 'var(--accent-yellow, #f59e0b)' },
  trust: { label: 'Trust', bg: 'rgba(239,68,68,0.08)', fg: 'var(--accent-red)' },
}

/* ── Conversation list item ── */
function ConversationListItem({
  conv,
  isActive,
  onClick,
}: {
  conv: ConversationSummary
  isActive: boolean
  onClick: () => void
}) {
  const { t } = useLocale()

  function formatRelativeTime(ts: string | null): string {
    if (!ts) return ''
    const d = new Date(ts)
    if (isNaN(d.getTime())) return ''
    const diff = Date.now() - d.getTime()
    const mins = Math.floor(diff / 60000)
    if (mins < 1) return t('time.now')
    if (mins < 60) return t('time.minutes', { n: mins })
    const hours = Math.floor(mins / 60)
    if (hours < 24) return t('time.hours', { n: hours })
    const days = Math.floor(hours / 24)
    return t('time.days', { n: days })
  }

  const isDm = conv.kind === 'dm'
  const title = isDm ? conv.peer_name : conv.peer_name
  const kindLabel = isDm ? 'DM' : 'Group'
  const kindColor = isDm ? 'var(--accent-blue)' : 'var(--accent-green)'

  return (
    <button
      onClick={onClick}
      className="w-full text-left px-3 py-2.5 transition-colors duration-100"
      style={{
        background: isActive ? 'var(--bg-tertiary)' : 'transparent',
        borderRadius: 'var(--radius-md)',
        border: 'none',
        cursor: 'pointer',
      }}
    >
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-1.5 min-w-0">
          <span
            className="text-xs px-1 py-0.5 flex-shrink-0"
            style={{
              background: `color-mix(in srgb, ${kindColor} 12%, transparent)`,
              color: kindColor,
              borderRadius: 'var(--radius-sm)',
              fontSize: 9,
              fontWeight: 600,
            }}
          >
            {kindLabel}
          </span>
          <span
            className="text-sm truncate font-medium"
            style={{ color: isActive ? 'var(--text-primary)' : 'var(--text-secondary)' }}
          >
            {title}
          </span>
        </div>
        <span
          className="text-xs flex-shrink-0 ml-2"
          style={{ color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: 10 }}
        >
          {formatRelativeTime(conv.last_message_at)}
        </span>
      </div>
      {conv.last_message && (
        <div
          className="text-xs truncate mt-0.5"
          style={{ color: 'var(--text-muted)', maxWidth: '100%' }}
        >
          {conv.last_message.content}
        </div>
      )}
      <div className="flex items-center gap-2 mt-1">
        {isDm && conv.trust_tier && (
          <span className="text-xs" style={{ color: 'var(--text-muted)', fontSize: 10 }}>
            Trust: {conv.trust_tier}
          </span>
        )}
        {conv.collab_active && (
          <span
            className="text-xs px-1 py-0.5"
            style={{
              background: 'rgba(34,197,94,0.12)',
              color: 'var(--accent-green)',
              borderRadius: 'var(--radius-sm)',
              fontSize: 9,
              fontWeight: 600,
            }}
          >
            Collab
          </span>
        )}
        <span className="text-xs" style={{ color: 'var(--text-muted)', fontSize: 10 }}>
          {conv.message_count} msg{conv.message_count !== 1 ? 's' : ''}
        </span>
        {conv.unread_count > 0 && (
          <span
            className="text-xs px-1.5 py-0.5"
            style={{
              background: 'var(--accent-blue)',
              color: 'white',
              borderRadius: 'var(--radius-sm)',
              fontSize: 10,
              fontWeight: 600,
            }}
          >
            {conv.unread_count}
          </span>
        )}
      </div>
    </button>
  )
}

/* ── DM Message Item (protocol-aware) ── */
function DmMessageItem({ message, isSelf: _isSelf }: { message: DmMessage; isSelf: boolean }) {
  const phase = phaseBadge[message.phase]
  const isOutbound = message.direction === 'outbound'
  const color = isOutbound ? 'var(--accent-blue)' : 'var(--text-secondary)'

  function formatTime(ts: string): string {
    if (!ts) return ''
    const d = new Date(ts)
    if (isNaN(d.getTime())) return ''
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
  }

  return (
    <div className={`flex gap-2.5 px-4 py-1.5 ${isOutbound ? 'flex-row-reverse' : ''}`}>
      {/* Direction indicator */}
      <div
        className="w-7 h-7 flex items-center justify-center flex-shrink-0 text-xs"
        style={{
          borderRadius: 'var(--radius-sm)',
          background: `color-mix(in srgb, ${color} 15%, transparent)`,
          color,
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: 11,
        }}
      >
        {isOutbound ? '→' : '←'}
      </div>

      <div className={`max-w-[75%] ${isOutbound ? 'text-right' : ''}`}>
        {/* Header: sender + phase badge + msg_type + time */}
        <div
          className="flex items-center gap-1.5 mb-0.5 flex-wrap"
          style={{ flexDirection: isOutbound ? 'row-reverse' : 'row' }}
        >
          <span className="text-xs font-medium" style={{ color }}>
            {isOutbound ? 'You' : message.sender_name}
          </span>
          {phase && (
            <span
              className="text-xs px-1 py-0.5"
              style={{
                background: phase.bg,
                color: phase.fg,
                borderRadius: 'var(--radius-sm)',
                fontSize: 9,
                fontWeight: 600,
              }}
            >
              {phase.label}
            </span>
          )}
          <span
            className="text-xs px-1 py-0.5"
            style={{
              background: 'var(--bg-tertiary)',
              color: 'var(--text-muted)',
              borderRadius: 'var(--radius-sm)',
              fontSize: 9,
              fontFamily: "'JetBrains Mono', monospace",
            }}
          >
            {message.msg_type}
          </span>
          {message.skill && (
            <span
              className="text-xs"
              style={{ color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: 10 }}
            >
              {message.skill}
            </span>
          )}
          <span
            className="text-xs"
            style={{ color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: 10 }}
          >
            {formatTime(message.created_at)}
          </span>
        </div>

        {/* Content bubble */}
        <div
          className="text-sm px-3 py-2 inline-block"
          style={{
            background: isOutbound ? 'var(--accent-blue)' : 'var(--bg-secondary)',
            color: isOutbound ? 'white' : 'var(--text-primary)',
            borderRadius: 'var(--radius-md)',
            textAlign: 'left',
            wordBreak: 'break-word',
            whiteSpace: 'pre-wrap',
          }}
        >
          {message.content}
        </div>
      </div>
    </div>
  )
}

/* ── Main Chat Page ── */
export function ChatPage() {
  const { t } = useLocale()
  const [selectedConvId, setSelectedConvId] = useState<string | null>(null)
  const [showMembers, setShowMembers] = useState(false)
  const [selfWallet, setSelfWallet] = useState('')

  // Fetch agent profile for self wallet
  const { data: profile } = useQuery({
    queryKey: ['agent-profile'],
    queryFn: fetchAgentProfile,
  })
  useEffect(() => {
    if (profile?.wallet) setSelfWallet(profile.wallet)
  }, [profile])

  // Fetch conversations list (5s polling)
  const { data: convsRes, isLoading: convsLoading } = useQuery({
    queryKey: ['conversations'],
    queryFn: fetchConversations,
    refetchInterval: 5000,
  })
  const conversations = convsRes?.conversations ?? []

  // Auto-select first conversation
  useEffect(() => {
    if (!selectedConvId && conversations.length > 0) {
      setSelectedConvId(conversations[0].id)
    }
  }, [selectedConvId, conversations])

  const selectedConv = conversations.find(c => c.id === selectedConvId)
  const isGroupConv = selectedConv?.kind === 'group'
  const groupId = isGroupConv && selectedConvId ? selectedConvId.replace('group:', '') : null

  // Fetch group detail for member sidebar (only for group conversations)
  const { data: groupDetail } = useQuery({
    queryKey: ['group-detail', groupId],
    queryFn: () => fetchGroupDetail(groupId!),
    enabled: !!groupId,
    refetchInterval: 10000,
  })
  const members: GroupMember[] = groupDetail?.members ?? []

  // Messages (2s polling)
  const { data: messages = [], isLoading: messagesLoading, resetCursor } = useConversationMessagesQuery(
    selectedConvId,
    2000,
  )

  const handleSelectConv = useCallback(
    (id: string) => {
      if (id !== selectedConvId) {
        setSelectedConvId(id)
        resetCursor()
      }
    },
    [selectedConvId, resetCursor],
  )

  // Adapt messages for MessageList (normalize DM messages to ChatMessage-like shape)
  const normalizedMessages: ChatMessage[] = messages.map((m: any) => {
    if (m.conversation_kind === 'dm' || m.direction) {
      // DM message → ChatMessage shape
      const dm = m as DmMessage
      return {
        id: dm.id,
        client_message_id: '',
        group_id: dm.conversation_id,
        sender_wallet: dm.sender_wallet,
        sender_name: dm.sender_name,
        sender_trust_tier: dm.direction === 'outbound' ? 'self' : 'known',
        content: dm.content,
        content_type: dm.content_type,
        created_at: dm.created_at,
        server_received_at: dm.server_received_at,
        delivery_status: dm.delivery_status,
      } as ChatMessage
    }
    return m as ChatMessage
  })

  // For DM conversations, render DmMessageItem directly
  const isDmConv = selectedConv?.kind === 'dm'

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.2 }}
      className="flex h-[calc(100vh-120px)]"
      style={{
        border: '1px solid var(--border)',
        borderRadius: 'var(--radius-lg)',
        overflow: 'hidden',
        background: 'var(--bg-primary)',
      }}
    >
      {/* Conversation list sidebar */}
      <div
        className="w-64 flex-shrink-0 flex flex-col overflow-y-auto"
        style={{
          borderRight: '1px solid var(--border)',
          background: 'var(--bg-secondary)',
        }}
      >
        <div className="px-4 py-3" style={{ borderBottom: '1px solid var(--border)' }}>
          <h2
            className="text-lg tracking-tight"
            style={{ fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif", color: 'var(--text-primary)' }}
          >
            {t('chat.title')}
          </h2>
          <div className="text-xs mt-0.5" style={{ color: 'var(--text-muted)' }}>
            {conversations.length} conversation{conversations.length !== 1 ? 's' : ''}
          </div>
        </div>
        <div className="flex-1 px-2 py-2 space-y-0.5">
          {convsLoading ? (
            <div className="text-sm px-3 py-4" style={{ color: 'var(--text-muted)' }}>
              {t('chat.loadingGroups')}
            </div>
          ) : conversations.length === 0 ? (
            <div className="px-3 py-4">
              <EmptyState
                title={t('chat.noGroups')}
                description="Start a collaboration to see messages here"
                compact
              />
            </div>
          ) : (
            conversations.map(c => (
              <ConversationListItem
                key={c.id}
                conv={c}
                isActive={c.id === selectedConvId}
                onClick={() => handleSelectConv(c.id)}
              />
            ))
          )}
        </div>
      </div>

      {/* Main chat area */}
      {selectedConv ? (
        <div className="flex-1 flex flex-col min-w-0">
          <ChatHeader
            groupName={`${selectedConv.kind === 'dm' ? '💬 ' : '👥 '}${selectedConv.peer_name}`}
            memberCount={selectedConv.member_count ?? 2}
            onToggleMembers={isGroupConv ? () => setShowMembers(prev => !prev) : undefined}
          />
          <div className="flex-1 flex min-h-0">
            <div className="flex-1 flex flex-col min-w-0">
              {isDmConv ? (
                /* DM: protocol-aware message rendering */
                <div className="flex-1 overflow-y-auto py-3 space-y-1">
                  {messagesLoading ? (
                    <div className="text-sm text-center py-8" style={{ color: 'var(--text-muted)' }}>
                      Loading messages...
                    </div>
                  ) : messages.length === 0 ? (
                    <div className="text-sm text-center py-8" style={{ color: 'var(--text-muted)' }}>
                      No messages yet. Start a collaboration to see protocol messages.
                    </div>
                  ) : (
                    (messages as DmMessage[]).map(m => (
                      <DmMessageItem
                        key={m.id}
                        message={m}
                        isSelf={m.direction === 'outbound'}
                      />
                    ))
                  )}
                </div>
              ) : (
                /* Group: existing MessageList rendering */
                <MessageList
                  messages={normalizedMessages}
                  selfWallet={selfWallet}
                  isLoading={messagesLoading}
                  groupId={groupId ?? null}
                />
              )}
              <Composer />
            </div>
            {showMembers && isGroupConv && (
              <MemberSidebar members={members} selfWallet={selfWallet} />
            )}
          </div>
        </div>
      ) : (
        <div className="flex-1 flex items-center justify-center">
          <EmptyState
            title={t('chat.selectGroup')}
            description="Select a conversation to view messages"
          />
        </div>
      )}
    </motion.div>
  )
}
