import { useLocale } from '../../../lib/i18n'
import type { ChatMessage } from '../../../lib/types'

function formatTime(ts: string): string {
  if (!ts) return ''
  const d = new Date(ts)
  if (isNaN(d.getTime())) return ''
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
}

function trustColor(tier: string | number): string {
  if (tier === 'self') return 'var(--accent-blue)'
  if (tier === 'privileged' || tier === 3) return 'var(--accent-purple)'
  if (tier === 'internal' || tier === 2) return 'var(--accent-green)'
  if (tier === 'known' || tier === 1) return 'var(--text-secondary)'
  return 'var(--text-muted)'
}

function avatarLetter(name: string): string {
  return (name || '?')[0].toUpperCase()
}

interface MessageItemProps {
  message: ChatMessage
  isSelf: boolean
}

export function MessageItem({ message, isSelf }: MessageItemProps) {
  const { t } = useLocale()
  const color = trustColor(message.sender_trust_tier)
  const failed = message.delivery_status === 'failed'
  const pending = message.is_optimistic && message.delivery_status === 'pending'

  function trustBadge(tier: string | number): { label: string; bg: string; fg: string } | null {
    if (tier === 'self') return null
    if (tier === 'privileged' || tier === 3)
      return { label: 'Agent', bg: 'rgba(139, 92, 246, 0.1)', fg: 'var(--accent-purple)' }
    if (tier === 'internal' || tier === 2)
      return { label: 'Agent', bg: 'rgba(34, 197, 94, 0.1)', fg: 'var(--accent-green)' }
    if (tier === 'known' || tier === 1)
      return { label: 'Agent', bg: 'rgba(100, 116, 139, 0.1)', fg: 'var(--text-secondary)' }
    return { label: t('chat.unknown'), bg: 'rgba(239, 68, 68, 0.08)', fg: 'var(--accent-red)' }
  }

  const badge = trustBadge(message.sender_trust_tier)

  return (
    <div
      className={`flex gap-2.5 px-4 py-1.5 ${isSelf ? 'flex-row-reverse' : ''}`}
      style={{ opacity: pending ? 0.6 : 1 }}
    >
      {/* Avatar */}
      <div
        className="w-7 h-7 flex items-center justify-center flex-shrink-0 text-xs font-medium"
        style={{
          borderRadius: 'var(--radius-sm)',
          background: `color-mix(in srgb, ${color} 15%, transparent)`,
          color,
        }}
      >
        {avatarLetter(message.sender_name)}
      </div>

      {/* Content */}
      <div className={`max-w-[70%] ${isSelf ? 'text-right' : ''}`}>
        <div className="flex items-center gap-2 mb-0.5" style={{ flexDirection: isSelf ? 'row-reverse' : 'row' }}>
          <span className="text-xs font-medium" style={{ color }}>
            {isSelf ? t('chat.you') : message.sender_name}
          </span>
          {badge && (
            <span
              className="text-xs px-1 py-0.5"
              style={{
                background: badge.bg,
                color: badge.fg,
                borderRadius: 'var(--radius-sm)',
                fontSize: 9,
                fontWeight: 600,
                letterSpacing: '0.3px',
              }}
            >
              {badge.label}
            </span>
          )}
          <span
            className="text-xs"
            style={{ color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: 10 }}
          >
            {formatTime(message.created_at)}
          </span>
        </div>
        <div
          className="text-sm px-3 py-2 inline-block"
          style={{
            background: isSelf ? 'var(--accent-blue)' : 'var(--bg-secondary)',
            color: isSelf ? 'white' : 'var(--text-primary)',
            borderRadius: 'var(--radius-md)',
            textAlign: 'left',
            wordBreak: 'break-word',
            whiteSpace: 'pre-wrap',
          }}
        >
          {message.content}
        </div>
        {failed && (
          <div className="text-xs mt-0.5" style={{ color: 'var(--accent-red)' }}>
            {t('chat.failedToSend')}
          </div>
        )}
      </div>
    </div>
  )
}
