import { Outlet, NavLink } from 'react-router-dom'
import { useQuery } from '@tanstack/react-query'
import { StatusDot } from '../components/StatusDot'
import { fetchSessions } from '../lib/api/client'
import { useLocale } from '../lib/i18n'

export function Layout() {
  const { t, locale, setLocale } = useLocale()

  const NAV_ITEMS = [
    { to: '/', label: t('nav.home') },
    { to: '/goals', label: t('nav.goals') },
    { to: '/team', label: t('nav.team') },
    { to: '/insights', label: t('nav.insights') },
    { to: '/chat', label: t('nav.chat') },
  ]

  const BOTTOM_NAV = [
    { to: '/invite', label: t('nav.invite') },
    { to: '/settings', label: t('nav.settings') },
  ]

  const { data: pendingSessions } = useQuery({
    queryKey: ['sessions-proposed'],
    queryFn: () => fetchSessions({ state: 'proposed' }),
    refetchInterval: 15000,
  })
  const pendingCount = pendingSessions?.length || 0

  return (
    <div className="flex min-h-screen" style={{ background: 'var(--bg-primary)' }}>
      {/* Sidebar */}
      <aside
        className="w-60 flex-shrink-0 flex flex-col sticky top-0 h-screen"
        style={{
          background: 'var(--bg-secondary)',
          borderRight: '1px solid var(--border)',
        }}
      >
        {/* Brand masthead */}
        <div className="px-5 py-5">
          <h1
            className="text-2xl tracking-tight"
            style={{
              fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif",
              color: 'var(--text-primary)',
            }}
          >
            CoWorker
          </h1>
          <div className="flex items-center gap-2 mt-1">
            <span
              className="text-xs px-1.5 py-0.5"
              style={{
                background: 'var(--bg-primary)',
                color: 'var(--text-muted)',
                border: '1px solid var(--border)',
                borderRadius: 'var(--radius-sm)',
                fontSize: 10,
                fontWeight: 500,
                letterSpacing: '0.5px',
              }}
            >
              {t('nav.beta')}
            </span>
            <div className="flex items-center gap-1.5">
              <StatusDot status="online" size={6} />
              <span className="text-xs" style={{ color: 'var(--text-muted)' }}>{t('nav.online')}</span>
            </div>
          </div>
        </div>

        {/* Decorative accent */}
        <div className="px-5 mb-3">
          <div
            className="rounded-full"
            style={{ width: 20, height: 2, background: 'var(--accent-red)' }}
          />
        </div>

        {/* Main navigation */}
        <nav className="flex-1 px-3">
          <div className="space-y-0.5">
            {NAV_ITEMS.map(({ to, label }) => (
              <NavLink
                key={to}
                to={to}
                end={to === '/'}
                className="relative flex items-center px-3 py-2 text-sm transition-colors duration-150"
                style={({ isActive }) => ({
                  color: isActive ? 'var(--text-primary)' : 'var(--text-muted)',
                  background: isActive ? 'var(--bg-tertiary)' : 'transparent',
                  borderRadius: 'var(--radius-md)',
                  fontWeight: isActive ? 600 : 400,
                })}
              >
                {({ isActive }) => (
                  <>
                    {isActive && (
                      <span
                        className="absolute left-0 top-1/2 -translate-y-1/2 rounded-r-full"
                        style={{
                          width: 3,
                          height: 16,
                          background: 'var(--accent-red)',
                        }}
                      />
                    )}
                    <span className="ml-1">{label}</span>
                    {to === '/' && pendingCount > 0 && (
                      <span
                        className="ml-auto text-xs px-1.5 py-0.5"
                        style={{
                          background: 'var(--accent-red-light)',
                          color: 'var(--accent-red)',
                          border: '1px solid rgba(165, 25, 46, 0.15)',
                          borderRadius: 'var(--radius-sm)',
                          fontSize: 10,
                          fontWeight: 500,
                        }}
                      >
                        {pendingCount}
                      </span>
                    )}
                  </>
                )}
              </NavLink>
            ))}
          </div>
        </nav>

        {/* Bottom navigation */}
        <div className="px-3 pb-4">
          <div
            className="mb-3"
            style={{ height: 1, background: 'var(--border)' }}
          />
          {BOTTOM_NAV.map(({ to, label }) => (
            <NavLink
              key={to}
              to={to}
              className="flex items-center px-3 py-2 text-sm transition-colors duration-150"
              style={({ isActive }) => ({
                color: isActive ? 'var(--text-primary)' : 'var(--text-muted)',
                background: isActive ? 'var(--bg-tertiary)' : 'transparent',
                borderRadius: 'var(--radius-md)',
                fontWeight: isActive ? 600 : 400,
              })}
            >
              {label}
            </NavLink>
          ))}
          <div className="px-3 pt-2">
            <button
              onClick={() => setLocale(locale === 'zh' ? 'en' : 'zh')}
              className="px-2 py-1 text-xs font-medium transition-colors"
              style={{
                borderRadius: 'var(--radius-sm)',
                border: '1px solid var(--border)',
                background: 'var(--bg-secondary)',
                color: 'var(--text-secondary)',
              }}
            >
              {locale === 'zh' ? 'EN' : '中文'}
            </button>
          </div>
        </div>
      </aside>

      {/* Main content */}
      <div className="flex-1 flex flex-col min-w-0">
        {/* Top header bar */}
        <header
          className="flex items-center justify-between px-8 py-4"
          style={{ borderBottom: '1px solid var(--border)' }}
        >
          <div />
          <div className="flex items-center gap-3">
            {pendingCount > 0 && (
              <NavLink
                to="/"
                className="flex items-center gap-1.5 px-2 py-0.5 text-xs"
                style={{
                  background: 'var(--accent-red-light)',
                  color: 'var(--accent-red)',
                  border: '1px solid rgba(165, 25, 46, 0.15)',
                  borderRadius: 'var(--radius-sm)',
                  fontWeight: 500,
                }}
              >
                {pendingCount} {t('nav.pending')}
              </NavLink>
            )}
          </div>
        </header>

        {/* Page content */}
        <main className="flex-1 px-8 py-6 lg:px-10" style={{ background: 'var(--bg-primary)' }}>
          <Outlet />
        </main>
      </div>
    </div>
  )
}
