import { PRIVACY_COLORS } from '../../lib/constants'
import { useLocale } from '../../lib/i18n'
import type { ContextPolicy, ContextPolicyUpdate } from '../../lib/api/client'

interface ContextPolicyEditorProps {
  policy: Partial<ContextPolicy>
  onUpdate: (update: ContextPolicyUpdate) => void
  saving?: boolean
}

const CATEGORIES = ['general', 'project', 'credentials', 'personal', 'system']
const PRIVACY_OPTIONS = ['L1_PUBLIC', 'L2_TRUSTED', 'L3_PRIVATE'] as const

const PRIVACY_I18N_KEY: Record<string, string> = {
  L1_PUBLIC: 'privacy.public',
  L2_TRUSTED: 'privacy.trusted',
  L3_PRIVATE: 'privacy.private',
}

export function ContextPolicyEditor({ policy, onUpdate, saving }: ContextPolicyEditorProps) {
  const { t } = useLocale()
  const categoryPolicies = policy.category_policies || {}

  function handleChange(category: string, privacyTier: string) {
    onUpdate({
      category_policies: { ...categoryPolicies, [category]: privacyTier },
    })
  }

  return (
    <div
      className="p-5"
      style={{ boxShadow: 'var(--shadow-sm)', borderRadius: 'var(--radius-md)', background: 'var(--bg-primary)' }}
    >
      <h3
        className="text-base font-semibold mb-1"
        style={{ color: 'var(--text-primary)' }}
      >
        {t('settings.contextPolicy')}
      </h3>
      <p className="text-xs mb-4" style={{ color: 'var(--text-muted)' }}>
        {t('settings.contextPolicyDesc')}
      </p>

      <div className="space-y-3">
        {CATEGORIES.map(cat => {
          const current = categoryPolicies[cat] || 'L2_TRUSTED'
          return (
            <div key={cat} className="flex items-center justify-between">
              <span className="text-sm" style={{ color: 'var(--text-primary)' }}>{t('settings.category.' + cat)}</span>
              <div className="flex gap-1.5">
                {PRIVACY_OPTIONS.map(opt => {
                  const active = current === opt
                  const color = PRIVACY_COLORS[opt] || 'var(--text-muted)'
                  return (
                    <button
                      key={opt}
                      onClick={() => handleChange(cat, opt)}
                      disabled={saving}
                      className="px-2 py-1 text-xs transition-colors"
                      style={{
                        borderRadius: 'var(--radius-sm)',
                        border: 'none',
                        background: active ? color : 'var(--bg-secondary)',
                        color: active ? 'white' : 'var(--text-muted)',
                        fontWeight: active ? 500 : 400,
                        opacity: saving ? 0.6 : 1,
                      }}
                    >
                      {t(PRIVACY_I18N_KEY[opt])}
                    </button>
                  )
                })}
              </div>
            </div>
          )
        })}
      </div>
    </div>
  )
}
