import { useState } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { motion } from 'framer-motion'
import {
  fetchStats,
  fetchActivity,
  fetchSessions,
  fetchTasks,
  postSessionAction,
} from '../../lib/api/client'
import { useLocale } from '../../lib/i18n'
import { PageHeader } from '../../components/PageHeader'
import { StatCard } from '../../components/StatCard'
import { EmptyState } from '../../components/EmptyState'
import { SESSION_STATE_COLORS, TASK_STATE_COLORS } from '../../lib/constants'
import { AgentIcon } from '../../components/AgentIcon'
import type { Session, Task, ActivityItem } from '../../lib/types'

// ── Animation constants ─────────────────────────────────

const CONTAINER_VARIANTS = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: { staggerChildren: 0.06, ease: 'easeOut' as const },
  },
}

const ITEM_VARIANTS = {
  hidden: { opacity: 0, y: 12 },
  show: { opacity: 1, y: 0, transition: { duration: 0.3, ease: 'easeOut' as const } },
}

// ── Activity type config ────────────────────────────────

const ACTIVITY_TYPES = ['all', 'message', 'task', 'session', 'trust', 'workflow'] as const
type ActivityFilter = (typeof ACTIVITY_TYPES)[number]

// ── Relative time helper ────────────────────────────────

function relativeTime(iso: string, t: (key: string, params?: Record<string, string | number>) => string): string {
  const diff = Date.now() - new Date(iso).getTime()
  const seconds = Math.floor(diff / 1000)
  if (seconds < 60) return t('time.justNow')
  const minutes = Math.floor(seconds / 60)
  if (minutes < 60) return t('time.minutesAgo', { n: minutes })
  const hours = Math.floor(minutes / 60)
  if (hours < 24) return t('time.hoursAgo', { n: hours })
  const days = Math.floor(hours / 24)
  return t('time.daysAgo', { n: days })
}

// ── Approval Item Row ───────────────────────────────────

function ApprovalRow({
  type,
  label,
  sublabel,
  statusColor,
  statusText,
  actions,
}: {
  type: 'session' | 'task'
  label: string
  sublabel: string
  statusColor: string
  statusText: string
  actions?: React.ReactNode
}) {
  return (
    <motion.div
      variants={ITEM_VARIANTS}
      style={{
        background: 'var(--bg-secondary)',
        borderRadius: 'var(--radius-md)',
        border: '1px solid var(--border)',
        padding: '14px 16px',
        display: 'flex',
        alignItems: 'center',
        gap: 12,
        transition: 'border-color 0.15s ease',
      }}
      whileHover={{ borderColor: 'var(--accent-red)' }}
    >
      <AgentIcon name={type === 'session' ? label : 'task'} size={28} />

      {/* content */}
      <div style={{ flex: 1, minWidth: 0 }}>
        <div
          style={{
            fontSize: 14,
            fontWeight: 500,
            color: 'var(--text-primary)',
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          }}
        >
          {label}
        </div>
        <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>{sublabel}</div>
      </div>

      {/* status pill */}
      <span
        style={{
          fontSize: 11,
          fontWeight: 600,
          padding: '2px 8px',
          borderRadius: 999,
          background: statusColor,
          color: '#fff',
          flexShrink: 0,
        }}
      >
        {statusText}
      </span>

      {/* action buttons */}
      {actions && <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>{actions}</div>}
    </motion.div>
  )
}

// ── Activity Row ────────────────────────────────────────

function ActivityRow({ item }: { item: ActivityItem }) {
  const { t } = useLocale()

  return (
    <motion.div
      variants={ITEM_VARIANTS}
      style={{
        background: 'var(--bg-secondary)',
        borderRadius: 'var(--radius-md)',
        border: '1px solid var(--border)',
        padding: '10px 14px',
        display: 'flex',
        alignItems: 'center',
        gap: 10,
        transition: 'border-color 0.15s ease',
      }}
      whileHover={{ borderColor: 'var(--accent-red)' }}
    >
      <AgentIcon name={item.peer || item.type} size={28} />

      {/* content */}
      <div style={{ flex: 1, minWidth: 0 }}>
        <div
          style={{
            fontSize: 13,
            fontWeight: 500,
            color: 'var(--text-primary)',
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          }}
        >
          {item.title}
        </div>
        {item.description && (
          <div
            style={{
              fontSize: 12,
              color: 'var(--text-muted)',
              marginTop: 1,
              whiteSpace: 'nowrap',
              overflow: 'hidden',
              textOverflow: 'ellipsis',
            }}
          >
            {item.description}
          </div>
        )}
      </div>

      {/* peer tag */}
      {item.peer && (
        <span style={{ fontSize: 11, color: 'var(--text-secondary)', flexShrink: 0 }}>
          {item.peer}
        </span>
      )}

      {/* relative time */}
      <span style={{ fontSize: 11, color: 'var(--text-muted)', flexShrink: 0, minWidth: 48, textAlign: 'right' }}>
        {relativeTime(item.timestamp, t)}
      </span>
    </motion.div>
  )
}

// ── Main Page ───────────────────────────────────────────

export function HomePage() {
  const queryClient = useQueryClient()
  const { t } = useLocale()
  const [activityFilter, setActivityFilter] = useState<ActivityFilter>('all')

  // ── Data fetching ───────────────────────────────────

  const { data: stats } = useQuery({
    queryKey: ['stats'],
    queryFn: fetchStats,
    refetchInterval: 15_000,
  })

  const { data: proposedSessions = [] } = useQuery({
    queryKey: ['sessions', 'proposed'],
    queryFn: () => fetchSessions({ state: 'proposed' }),
    refetchInterval: 10_000,
  })

  const { data: failedTasks = [] } = useQuery({
    queryKey: ['tasks', 'failed'],
    queryFn: () => fetchTasks({ state: 'failed', limit: 10 }),
    refetchInterval: 15_000,
  })

  const { data: activity = [] } = useQuery({
    queryKey: ['activity'],
    queryFn: () => fetchActivity(20),
    refetchInterval: 12_000,
  })

  // ── Mutations ───────────────────────────────────────

  const sessionAction = useMutation({
    mutationFn: ({ id, action }: { id: string; action: 'accept' | 'reject' }) =>
      postSessionAction(id, action),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
      queryClient.invalidateQueries({ queryKey: ['stats'] })
      queryClient.invalidateQueries({ queryKey: ['activity'] })
    },
  })

  // ── Derived values ──────────────────────────────────

  const approvalCount = proposedSessions.length + failedTasks.length
  const completedTasks = stats?.task_states?.completed ?? 0
  const inProgress = (stats?.task_states?.in_progress ?? 0) + (stats?.task_states?.accepted ?? 0)
  const timeSaved = (completedTasks * 0.6).toFixed(1)

  const filteredActivity =
    activityFilter === 'all' ? activity : activity.filter((a) => a.type === activityFilter)

  // ── Render ──────────────────────────────────────────

  return (
    <div>
      <PageHeader title={t('home.title')} description={t('home.desc')} />

      {/* ── Section 1: Approval Queue ─────────────────── */}
      <motion.section
        variants={CONTAINER_VARIANTS}
        initial="hidden"
        animate="show"
        style={{ marginBottom: 28 }}
      >
        <motion.div variants={ITEM_VARIANTS}>
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 10,
              marginBottom: 12,
            }}
          >
            <div
              style={{
                width: 4,
                height: 20,
                borderRadius: 2,
                background: 'var(--accent-yellow)',
              }}
            />
            <h3
              style={{
                margin: 0,
                fontSize: 15,
                fontWeight: 600,
                fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif",
                color: 'var(--text-primary)',
              }}
            >
              {t('home.needsAttention')}{approvalCount > 0 ? ` (${approvalCount})` : ''}
            </h3>
          </div>
        </motion.div>

        {approvalCount === 0 ? (
          <motion.div variants={ITEM_VARIANTS}>
            <EmptyState
              title={t('home.allGood')}
              description={t('home.allGoodDesc')}
              compact
            />
          </motion.div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
            {/* Proposed sessions */}
            {proposedSessions.map((s: Session) => (
              <ApprovalRow
                key={s.session_id}
                type="session"
                label={t('home.sessionFrom', { peer: s.peer_id })}
                sublabel={`${t('home.skillsLabel', { skills: s.proposed_skills.join(', ') || t('common.none') })} · ${relativeTime(s.created_at, t)}`}
                statusColor={SESSION_STATE_COLORS.proposed}
                statusText={t('session.proposed')}
                actions={
                  <>
                    <button
                      onClick={() =>
                        sessionAction.mutate({ id: s.session_id, action: 'accept' })
                      }
                      disabled={sessionAction.isPending}
                      style={{
                        padding: '4px 12px',
                        fontSize: 12,
                        fontWeight: 600,
                        borderRadius: 'var(--radius-sm)',
                        border: 'none',
                        cursor: 'pointer',
                        background: 'var(--accent-green)',
                        color: '#fff',
                        opacity: sessionAction.isPending ? 0.6 : 1,
                      }}
                    >
                      {t('home.accept')}
                    </button>
                    <button
                      onClick={() =>
                        sessionAction.mutate({ id: s.session_id, action: 'reject' })
                      }
                      disabled={sessionAction.isPending}
                      style={{
                        padding: '4px 12px',
                        fontSize: 12,
                        fontWeight: 600,
                        borderRadius: 'var(--radius-sm)',
                        border: 'none',
                        cursor: 'pointer',
                        background: 'var(--accent-red)',
                        color: '#fff',
                        opacity: sessionAction.isPending ? 0.6 : 1,
                      }}
                    >
                      {t('home.reject')}
                    </button>
                  </>
                }
              />
            ))}

            {/* Failed tasks */}
            {failedTasks.map((task: Task) => (
              <ApprovalRow
                key={task.task_id}
                type="task"
                label={t('home.taskFailed', { skill: task.skill })}
                sublabel={`${task.peer_name} · ${task.error_message || t('home.unknownError')} · ${relativeTime(task.created_at, t)}`}
                statusColor={TASK_STATE_COLORS.failed}
                statusText={t('wf.failed')}
              />
            ))}
          </div>
        )}
      </motion.section>

      {/* ── Section 2: Today's Summary (KPI strip) ────── */}
      <motion.section
        variants={CONTAINER_VARIANTS}
        initial="hidden"
        animate="show"
        style={{ marginBottom: 28 }}
      >
        <motion.div variants={ITEM_VARIANTS}>
          <h3
            style={{
              margin: 0,
              marginBottom: 12,
              fontSize: 13,
              fontWeight: 600,
              fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif",
              color: 'var(--text-muted)',
              textTransform: 'uppercase',
              letterSpacing: '0.04em',
            }}
          >
            {t('home.todaySummary')}
          </h3>
        </motion.div>
        <motion.div
          variants={CONTAINER_VARIANTS}
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(4, 1fr)',
            gap: 12,
          }}
        >
          <motion.div variants={ITEM_VARIANTS}>
            <StatCard
              label={t('home.completedTasks')}
              value={completedTasks}
              color="var(--accent-green)"
            />
          </motion.div>
          <motion.div variants={ITEM_VARIANTS}>
            <StatCard
              label={t('home.inProgress')}
              value={inProgress}
              color="var(--accent-red)"
            />
          </motion.div>
          <motion.div variants={ITEM_VARIANTS}>
            <StatCard
              label={t('home.onlineAgents')}
              value={stats?.peer_count ?? 0}
              sublabel={t('home.activeSessions', { n: stats?.active_sessions ?? 0 })}
            />
          </motion.div>
          <motion.div variants={ITEM_VARIANTS}>
            <StatCard
              label={t('home.timeSaved')}
              value={`${timeSaved}h`}
              sublabel={t('home.estimated')}
              color="var(--accent-yellow)"
            />
          </motion.div>
        </motion.div>
      </motion.section>

      {/* ── Section 3: Activity Feed ──────────────────── */}
      <motion.section variants={CONTAINER_VARIANTS} initial="hidden" animate="show">
        <motion.div
          variants={ITEM_VARIANTS}
          style={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            marginBottom: 12,
          }}
        >
          <h3
            style={{
              margin: 0,
              fontSize: 13,
              fontWeight: 600,
              fontFamily: "'Inter', 'Noto Sans SC', system-ui, sans-serif",
              color: 'var(--text-muted)',
              textTransform: 'uppercase',
              letterSpacing: '0.04em',
            }}
          >
            {t('home.recentActivity')}
          </h3>

          {/* Filter pills */}
          <div style={{ display: 'flex', gap: 4 }}>
            {ACTIVITY_TYPES.map((type) => {
              const active = activityFilter === type
              return (
                <button
                  key={type}
                  onClick={() => setActivityFilter(type)}
                  style={{
                    padding: '3px 10px',
                    fontSize: 11,
                    fontWeight: 600,
                    borderRadius: 999,
                    border: 'none',
                    cursor: 'pointer',
                    background: active ? 'var(--accent-red)' : 'var(--bg-secondary)',
                    color: active ? '#fff' : 'var(--text-secondary)',
                    transition: 'all 0.15s ease',
                  }}
                >
                  {t('activityType.' + type)}
                </button>
              )
            })}
          </div>
        </motion.div>

        {filteredActivity.length === 0 ? (
          <motion.div variants={ITEM_VARIANTS}>
            <EmptyState
              title={t('home.noActivity')}
              description={t('home.noActivityDesc')}
            />
          </motion.div>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {filteredActivity.map((item, i) => (
              <ActivityRow key={`${item.id}-${i}`} item={item} />
            ))}
          </div>
        )}
      </motion.section>
    </div>
  )
}
