import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { motion, AnimatePresence } from 'framer-motion'
import { fetchPeerDetail, patchTrust } from '../../lib/api/client'
import { StatusDot } from '../../components/StatusDot'
import { TrustBadge } from '../../components/TrustBadge'
import { TRUST_TIER_LABELS, TRUST_TIER_COLORS } from '../../lib/constants'
import { useLocale } from '../../lib/i18n'
import { TrustTier } from '../../lib/types'

interface PeerDrawerProps {
  peerId: string
  onClose: () => void
}

const TRUST_TIERS = [
  TrustTier.UNTRUSTED,
  TrustTier.KNOWN,
  TrustTier.INTERNAL,
  TrustTier.PRIVILEGED,
] as const

export function PeerDrawer({ peerId, onClose }: PeerDrawerProps) {
  const { t } = useLocale()
  const queryClient = useQueryClient()
  const { data: peer, isLoading } = useQuery({
    queryKey: ['peer-detail', peerId],
    queryFn: () => fetchPeerDetail(peerId),
  })

  const trustMutation = useMutation({
    mutationFn: (tier: number) => patchTrust(peerId, tier),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['peer-detail', peerId] })
      queryClient.invalidateQueries({ queryKey: ['peers'] })
    },
  })

  const rep = peer?.reputation ?? {}

  return (
    <AnimatePresence>
      <div
        className="fixed inset-0 z-50 flex"
        onClick={(e) => { if (e.target === e.currentTarget) onClose() }}
      >
        {/* Backdrop */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="flex-1"
          style={{ background: 'rgba(0, 0, 0, 0.4)' }}
          onClick={onClose}
        />

        {/* Drawer panel */}
        <motion.div
          initial={{ x: '100%' }}
          animate={{ x: 0 }}
          exit={{ x: '100%' }}
          transition={{ duration: 0.25, ease: 'easeOut' }}
          className="w-full max-w-md overflow-y-auto p-6"
          style={{ background: 'var(--bg-primary)', boxShadow: 'var(--shadow-sm)' }}
        >
          <div className="flex items-center justify-between mb-6">
            <h2
              className="text-xl font-semibold"
              style={{ color: 'var(--text-primary)' }}
            >
              {peerId}
            </h2>
            <button
              onClick={onClose}
              className="text-xs px-2 py-1"
              style={{ color: 'var(--text-muted)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-sm)', border: 'none' }}
            >
              {t('peers.close')}
            </button>
          </div>

          {isLoading ? (
            <div className="text-sm" style={{ color: 'var(--text-muted)' }}>{t('peers.loading')}</div>
          ) : !peer || peer.error ? (
            <div className="text-sm" style={{ color: 'var(--accent-red)' }}>{peer?.error || t('common.noData')}</div>
          ) : (
            <div className="space-y-6">
              <div className="flex items-center gap-3">
                <StatusDot status={peer.is_online ? 'online' : 'offline'} size={10} />
                <span className="text-sm" style={{ color: 'var(--text-primary)' }}>{peer.is_online ? t('nav.online') : 'Offline'}</span>
                {peer.latency_ms != null && (
                  <span className="text-xs" style={{ color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace" }}>
                    {peer.latency_ms.toFixed(0)}ms
                  </span>
                )}
              </div>

              {/* Trust Level */}
              <div>
                <h3
                  className="text-sm font-medium mb-2"
                  style={{ color: 'var(--text-secondary)' }}
                >
                  {t('peers.trustLevel')}
                </h3>
                <div className="flex gap-1.5">
                  {TRUST_TIERS.map(tier => {
                    const active = peer.trust_tier === tier
                    const color = TRUST_TIER_COLORS[tier]
                    return (
                      <button
                        key={tier}
                        onClick={() => trustMutation.mutate(tier)}
                        disabled={trustMutation.isPending}
                        className="px-3 py-1.5 text-xs transition-colors font-medium"
                        style={{
                          borderRadius: 'var(--radius-sm)',
                          border: 'none',
                          background: active ? `color-mix(in srgb, ${color} 10%, white)` : 'var(--bg-secondary)',
                          color: active ? color : 'var(--text-muted)',
                          opacity: trustMutation.isPending ? 0.6 : 1,
                        }}
                      >
                        {TRUST_TIER_LABELS[tier]}
                      </button>
                    )
                  })}
                </div>
              </div>

              {/* Reputation */}
              <div>
                <h3
                  className="text-sm font-medium mb-2"
                  style={{ color: 'var(--text-secondary)' }}
                >
                  {t('peers.reputation')}
                </h3>
                <div className="grid grid-cols-2 gap-2">
                  <RepStat label={t('peers.repSuccess')} value={
                    rep.success_rate != null ? `${(rep.success_rate * 100).toFixed(0)}%` : 'N/A'
                  } />
                  <RepStat label={t('peers.repFailed')} value={rep.failures ?? 0} />
                  <RepStat label={t('peers.repAvgLatency')} value={
                    rep.avg_latency_ms != null ? `${rep.avg_latency_ms.toFixed(0)}ms` : 'N/A'
                  } />
                  <RepStat label={t('peers.repLastSeen')} value={
                    rep.first_seen ? new Date(rep.first_seen).toLocaleDateString() : 'N/A'
                  } />
                </div>
              </div>

              {/* Skills */}
              {peer.skill_cards.length > 0 && (
                <div>
                  <h3
                    className="text-sm font-medium mb-2"
                    style={{ color: 'var(--text-secondary)' }}
                  >
                    {t('peers.skillsSection')} ({peer.skill_cards.length})
                  </h3>
                  <div className="space-y-2">
                    {peer.skill_cards.map(card => (
                      <div
                        key={card.skill_name}
                        className="p-3 text-sm"
                        style={{
                          boxShadow: 'var(--shadow-sm)',
                          background: 'var(--bg-primary)',
                          borderRadius: 'var(--radius-md)',
                        }}
                      >
                        <div className="flex items-center justify-between mb-1">
                          <span className="font-medium" style={{ color: 'var(--text-primary)' }}>{card.skill_name}</span>
                          <TrustBadge tier={card.min_trust_tier ?? 0} />
                        </div>
                        {card.description && (
                          <div className="text-xs" style={{ color: 'var(--text-muted)' }}>
                            {card.description}
                          </div>
                        )}
                      </div>
                    ))}
                  </div>
                </div>
              )}

              {/* Wallet */}
              {peer.wallet && (
                <div>
                  <h3
                    className="text-sm font-medium mb-1"
                    style={{ color: 'var(--text-secondary)' }}
                  >
                    {t('peers.wallet')}
                  </h3>
                  <span className="text-xs" style={{ fontFamily: "'JetBrains Mono', monospace", color: 'var(--text-muted)' }}>
                    {peer.wallet}
                  </span>
                </div>
              )}
            </div>
          )}
        </motion.div>
      </div>
    </AnimatePresence>
  )
}

function RepStat({ label, value }: { label: string; value: string | number }) {
  return (
    <div className="p-2" style={{ boxShadow: 'var(--shadow-sm)', borderRadius: 'var(--radius-sm)', background: 'var(--bg-primary)' }}>
      <div className="text-xs" style={{ color: 'var(--text-muted)' }}>{label}</div>
      <div className="text-sm font-medium" style={{ color: 'var(--text-primary)' }}>{value}</div>
    </div>
  )
}
