import { useRef, useEffect, useCallback } from 'react'
import { useLocale } from '../../../lib/i18n'
import { MessageItem } from './MessageItem'
import type { ChatMessage } from '../../../lib/types'

/** Threshold in pixels: if user is within this distance of the bottom, auto-scroll */
const SCROLL_THRESHOLD = 80

interface MessageListProps {
  messages: ChatMessage[]
  selfWallet: string
  isLoading: boolean
  groupId: string | null
}

export function MessageList({ messages, selfWallet, isLoading, groupId }: MessageListProps) {
  const { t } = useLocale()
  const bottomRef = useRef<HTMLDivElement>(null)
  const containerRef = useRef<HTMLDivElement>(null)
  const prevCountRef = useRef(0)
  const isNearBottomRef = useRef(true)

  // Track whether user is near the bottom of the scroll container
  const handleScroll = useCallback(() => {
    const el = containerRef.current
    if (!el) return
    const distanceFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight
    isNearBottomRef.current = distanceFromBottom <= SCROLL_THRESHOLD
  }, [])

  // Reset scroll state when switching groups
  useEffect(() => {
    prevCountRef.current = 0
    isNearBottomRef.current = true
    // Scroll to bottom immediately for new group
    bottomRef.current?.scrollIntoView()
  }, [groupId])

  // Auto-scroll to bottom only if user is already near the bottom
  useEffect(() => {
    if (messages.length > prevCountRef.current && isNearBottomRef.current) {
      bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
    }
    prevCountRef.current = messages.length
  }, [messages.length])

  if (isLoading && messages.length === 0) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <span className="text-sm" style={{ color: 'var(--text-muted)' }}>{t('chat.loadingMessages')}</span>
      </div>
    )
  }

  if (messages.length === 0) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <div className="text-center">
          <div className="text-sm" style={{ color: 'var(--text-muted)' }}>{t('chat.noMessages')}</div>
          <div className="text-xs mt-1" style={{ color: 'var(--text-muted)' }}>
            {t('chat.noMessagesDesc')}
          </div>
        </div>
      </div>
    )
  }

  return (
    <div
      ref={containerRef}
      onScroll={handleScroll}
      className="flex-1 overflow-y-auto py-4 space-y-1"
    >
      {messages.map(msg => (
        <MessageItem
          key={msg.id}
          message={msg}
          isSelf={msg.sender_wallet === selfWallet}
        />
      ))}
      <div ref={bottomRef} />
    </div>
  )
}
