interface EmptyStateProps {
  title: string;
  description?: string;
  compact?: boolean;
}

export function EmptyState({ title, description, compact }: EmptyStateProps) {
  return (
    <div
      className={`flex flex-col items-center justify-center px-6 ${compact ? 'py-6' : 'py-12'}`}
      style={{
        background: 'var(--bg-secondary)',
        borderRadius: 'var(--radius-md)',
        border: '1px dashed var(--border)',
      }}
    >
      <div className="text-sm font-medium mb-0.5" style={{ color: 'var(--text-muted)' }}>
        {title}
      </div>
      {description && (
        <div className="text-xs text-center max-w-xs" style={{ color: 'var(--text-muted)' }}>
          {description}
        </div>
      )}
    </div>
  )
}
